const input = $input.first().json;
const body = input.body || input;

const backendBaseUrl = String(body.backend_base_url || 'http://backend:8000').replace(/\/$/, '');
const agendaDate = String(body.agenda_date || '').trim();
const accessToken = String(body.access_token || '').trim();

if (!agendaDate) {
  throw new Error('agenda_date is required');
}
if (!accessToken) {
  throw new Error('access_token is required');
}

return [{
  json: {
    status: 'prepared',
    source: 'n8n_email_daily_agenda',
    agenda_date: agendaDate,
    backend_url: `${backendBaseUrl}/api/v1/notifications/email/send-direct?agenda_date=${encodeURIComponent(agendaDate)}`,
    authorization: `Bearer ${accessToken}`
  }
}];

const backendResponse = $input.first().json;
return [{
  json: {
    status: 'sent',
    source: 'n8n_email_daily_agenda',
    backend_response: backendResponse
  }
}];
